// Get all input items from the previous node (Extract from File)
const inputItems = items;

// ─── 1. EXTRACT RAW ROWS ───────────────────────────────────────────────────
const rawData = inputItems.map(item => item.json);

// ─── 2. DATA CLEANING ─────────────────────────────────────────────────────
const cleanedData = rawData.filter(row => {
  return (
    row["Order ID"] &&
    row["Sales"] !== undefined && row["Sales"] !== null && row["Sales"] !== "" &&
    row["Profit"] !== undefined && row["Profit"] !== null && row["Profit"] !== "" &&
    row["Region"] &&
    row["Category"]
  );
}).map(row => ({
  orderID:      row["Order ID"],
  orderDate:    row["Order Date"],
  region:       row["Region"],
  category:     row["Category"],
  subCategory:  row["Sub-Category"],
  sales:        parseFloat(row["Sales"]) || 0,
  profit:       parseFloat(row["Profit"]) || 0,
  quantity:     parseInt(row["Quantity"]) || 0,
  discount:     parseFloat(row["Discount"]) || 0,
  segment:      row["Segment"],
  state:        row["State"],
}));

// ─── 3. METRICS (EDA) ─────────────────────────────────────────────────────
const totalRows    = cleanedData.length;
const totalSales   = cleanedData.reduce((sum, r) => sum + r.sales, 0);
const totalProfit  = cleanedData.reduce((sum, r) => sum + r.profit, 0);
const profitMargin = totalSales > 0 ? ((totalProfit / totalSales) * 100).toFixed(2) : 0;
const avgSales     = totalRows > 0 ? (totalSales / totalRows).toFixed(2) : 0;
const avgDiscount  = totalRows > 0 ? (cleanedData.reduce((sum, r) => sum + r.discount, 0) / totalRows * 100).toFixed(2) : 0;

// Sales by Region
const salesByRegion = {};
cleanedData.forEach(r => {
  salesByRegion[r.region] = (salesByRegion[r.region] || 0) + r.sales;
});

// Sales by Category
const salesByCategory = {};
cleanedData.forEach(r => {
  salesByCategory[r.category] = (salesByCategory[r.category] || 0) + r.sales;
});

// Sales by Order Date (monthly trend)
const salesByMonth = {};
cleanedData.forEach(r => {
  if (r.orderDate) {
    const parts = r.orderDate.split("/");
    if (parts.length >= 3) {
      const monthKey = `${parts[2]}-${parts[0].padStart(2,"0")}`;
      salesByMonth[monthKey] = (salesByMonth[monthKey] || 0) + r.sales;
    }
  }
});
const sortedMonths = Object.keys(salesByMonth).sort();
const trendLabels  = sortedMonths;
const trendValues  = sortedMonths.map(m => parseFloat(salesByMonth[m].toFixed(2)));

// ─── 4. QUICK CHARTS (chart URLs via quickchart.io) ───────────────────────

// Chart 1: Sales by Region (Bar chart)
const regionLabels = Object.keys(salesByRegion);
const regionValues = regionLabels.map(k => parseFloat(salesByRegion[k].toFixed(2)));
const regionChartConfig = {
  type: "bar",
  data: {
    labels: regionLabels,
    datasets: [{
      label: "Sales by Region",
      data: regionValues,
      backgroundColor: ["#4e79a7","#f28e2b","#e15759","#76b7b2"]
    }]
  },
  options: { plugins: { legend: { display: true } } }
};
const regionChartURL = `https://quickchart.io/chart?c=${encodeURIComponent(JSON.stringify(regionChartConfig))}&width=600&height=400`;

// Chart 2: Sales by Category (Pie chart)
const categoryLabels = Object.keys(salesByCategory);
const categoryValues = categoryLabels.map(k => parseFloat(salesByCategory[k].toFixed(2)));
const categoryChartConfig = {
  type: "pie",
  data: {
    labels: categoryLabels,
    datasets: [{
      data: categoryValues,
      backgroundColor: ["#4e79a7","#f28e2b","#e15759"]
    }]
  },
  options: { plugins: { legend: { display: true } } }
};
const categoryChartURL = `https://quickchart.io/chart?c=${encodeURIComponent(JSON.stringify(categoryChartConfig))}&width=600&height=400`;

// Chart 3: Sales Trend by Month (Line chart)
const trendChartConfig = {
  type: "line",
  data: {
    labels: trendLabels,
    datasets: [{
      label: "Monthly Sales Trend",
      data: trendValues,
      borderColor: "#4e79a7",
      backgroundColor: "rgba(78,121,167,0.2)",
      fill: true
    }]
  },
  options: { plugins: { legend: { display: true } } }
};
const trendChartURL = `https://quickchart.io/chart?c=${encodeURIComponent(JSON.stringify(trendChartConfig))}&width=600&height=400`;

// ─── 5. HTML REPORT ───────────────────────────────────────────────────────
const reportHTML = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8"/>
  <title>Data Analyst Report</title>
  <style>
    body { font-family: Arial, sans-serif; margin: 40px; background: #f9f9f9; color: #333; }
    h1   { color: #4e79a7; }
    h2   { color: #e15759; border-bottom: 2px solid #eee; padding-bottom: 6px; }
    .metric-box { display:inline-block; background:#fff; border:1px solid #ddd;
                  border-radius:8px; padding:16px 24px; margin:8px;
                  box-shadow:1px 2px 6px rgba(0,0,0,0.06); text-align:center; }
    .metric-box h3 { margin:0 0 8px; font-size:13px; color:#888; }
    .metric-box p  { margin:0; font-size:22px; font-weight:bold; color:#4e79a7; }
    img { max-width:100%; border:1px solid #ddd; border-radius:8px; margin:12px 0; }
    ul  { line-height:1.8; }
  </style>
</head>
<body>
  <h1>📊 Data Analyst Report — Executive Summary</h1>

  <h2>Key Metrics</h2>
  <div class="metric-box"><h3>Total Rows</h3><p>${totalRows}</p></div>
  <div class="metric-box"><h3>Total Sales</h3><p>$${totalSales.toFixed(2)}</p></div>
  <div class="metric-box"><h3>Total Profit</h3><p>$${totalProfit.toFixed(2)}</p></div>
  <div class="metric-box"><h3>Profit Margin</h3><p>${profitMargin}%</p></div>
  <div class="metric-box"><h3>Avg Sales / Order</h3><p>$${avgSales}</p></div>
  <div class="metric-box"><h3>Avg Discount</h3><p>${avgDiscount}%</p></div>

  <h2>Sales by Region</h2>
  <img src="${regionChartURL}" alt="Sales by Region Chart"/>

  <h2>Sales by Category</h2>
  <img src="${categoryChartURL}" alt="Sales by Category Chart"/>

  <h2>Monthly Sales Trend</h2>
  <img src="${trendChartURL}" alt="Monthly Sales Trend Chart"/>

  <h2>Recommendations</h2>
  <ul>
    <li>Focus on top regions for revenue growth.</li>
    <li>Improve pricing or cost control to increase profit margin.</li>
    <li>Collect more time-series data for better trend analysis.</li>
    <li>Review high-discount orders that may be reducing profitability.</li>
  </ul>
</body>
</html>`;

// ─── 6. EMAIL BODY ────────────────────────────────────────────────────────
const emailBody = `Hi,

Hope you are doing well. Please find the automated AI Data Analyst Report generated from your uploaded dataset.

This report includes a quick summary of key metrics, visual insights, and actionable recommendations delivered straight from your data.

Key Highlights:
- Total Records Analyzed : ${totalRows}
- Total Sales            : $${totalSales.toFixed(2)}
- Total Profit           : $${totalProfit.toFixed(2)}
- Profit Margin          : ${profitMargin}%

The detailed HTML report and supporting charts are attached for deeper analysis.
Please check the file named report.html.

Best regards,
AI Data Analyst Agent`;

// ─── 7. RETURN OUTPUT ─────────────────────────────────────────────────────
return [
  {
    json: {
      charts: {
        salesByRegion:   regionChartURL,
        salesByCategory: categoryChartURL,
        salesByTrend:    trendChartURL,
      },
      reportHTML: reportHTML,
      emailBody:  emailBody,
      metrics: {
        totalRows,
        totalSales:   parseFloat(totalSales.toFixed(2)),
        totalProfit:  parseFloat(totalProfit.toFixed(2)),
        profitMargin: parseFloat(profitMargin),
        avgSales:     parseFloat(avgSales),
        avgDiscount:  parseFloat(avgDiscount),
      }
    }
  }
];
